const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,900;1,700&family=DM+Sans:wght@300;400;500;600;700&display=swap');

:root {
  --bg:       #0d0800;
  --surface:  #170e00;
  --card:     #1f1400;
  --card2:    #261a00;
  --amber:    #c8861a;
  --amber-l:  #e8a840;
  --amber-xs: rgba(200,134,26,0.12);
  --border:   rgba(200,134,26,0.16);
  --text:     #f0e0c0;
  --muted:    #9a7a55;
  --dim:      #5a4030;
  --white:    #ffffff;
  --green:    #10b981;
  --purple:   #8b5cf6;
  --red:      #ef4444;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }

body {
  font-family: 'DM Sans', sans-serif;
  background: var(--bg);
  color: var(--text);
  overflow-x: hidden;
  min-height: 100vh;
}

::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--amber); border-radius: 10px; }

/* ── ANIMATIONS ── */
@keyframes fadeUp    { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }
@keyframes shimmer   { 0%{background-position:200% 0} 100%{background-position:-200% 0} }
@keyframes orbDrift  { 0%,100%{transform:translate(0,0) scale(1)} 40%{transform:translate(40px,-30px) scale(1.08)} 70%{transform:translate(-20px,20px) scale(.96)} }
@keyframes blink     { 0%,100%{opacity:1} 50%{opacity:0.2} }
@keyframes scaleIn   { from{opacity:0;transform:scale(0.92)} to{opacity:1;transform:scale(1)} }

/* ── GALLERY PAGE ROOT ── */
.gal-root {
  min-height: 100vh;
  background: var(--bg);
  font-family: 'DM Sans', sans-serif;
  color: var(--text);
}

/* ── HERO ── */
.gal-hero {
  background: linear-gradient(160deg, #0d0500, #261200, #130800);
  padding: 80px 24px 100px;
  text-align: center;
  position: relative;
  overflow: hidden;
}
.gal-orb {
  position: absolute; border-radius: 50%;
  filter: blur(80px); opacity: 0.2;
  pointer-events: none; animation: orbDrift 14s ease-in-out infinite;
}
.gal-orb1 { width:450px;height:450px; background:radial-gradient(circle,#c8861a,transparent 70%); top:-120px;left:-80px; }
.gal-orb2 { width:350px;height:350px; background:radial-gradient(circle,#4a7a4a,transparent 70%); bottom:-80px;right:-60px; animation-delay:-7s; }
.gal-hero-wave {
  position: absolute; bottom: 0; left: 0; right: 0; height: 60px;
  background: var(--bg);
  clip-path: ellipse(58% 100% at 50% 100%);
}
.gal-hero-inner {
  position: relative; z-index: 2;
  max-width: 760px; margin: 0 auto;
}
.gal-pill {
  display: inline-flex; align-items: center; gap: 8px;
  background: rgba(200,134,26,0.12);
  border: 1px solid rgba(200,134,26,0.3);
  color: var(--amber-l);
  font-size: 0.72rem; font-weight: 700;
  letter-spacing: 0.18em; text-transform: uppercase;
  padding: 7px 20px; border-radius: 50px; margin-bottom: 24px;
}
.gal-dot { width:6px;height:6px; background:var(--amber-l); border-radius:50%; animation:blink 1.5s infinite; }
.gal-hero-inner h1 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(2.5rem, 5.5vw, 5rem);
  font-weight: 900; line-height: 1.08;
  color: var(--white); margin-bottom: 16px;
}
.gal-hero-inner h1 em { font-style: italic; color: var(--amber-l); }
.gal-hero-inner p {
  color: rgba(255,255,255,0.5);
  font-size: 1rem; font-weight: 300;
  max-width: 500px; margin: 0 auto 36px; line-height: 1.8;
}
.gal-hero-stats {
  display: flex; justify-content: center; gap: 48px; flex-wrap: wrap;
}
.gal-stat-num {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 700;
  color: var(--amber-l); display: block;
}
.gal-stat-lbl {
  font-size: 0.68rem; color: rgba(255,255,255,0.35);
  letter-spacing: 0.18em; text-transform: uppercase;
}

/* ── SEARCH BAR ── */
.gal-bar {
  max-width: 1140px; margin: -28px auto 0;
  padding: 0 24px; position: relative; z-index: 10;
}
.gal-bar-inner {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 20px; padding: 18px 22px;
  box-shadow: 0 12px 48px rgba(0,0,0,0.4);
  display: flex; gap: 12px; align-items: center; flex-wrap: wrap;
}
.gal-search {
  flex: 1; min-width: 180px;
  display: flex; align-items: center; gap: 10px;
  background: var(--card); border: 1.5px solid var(--border);
  border-radius: 50px; padding: 10px 18px; transition: 0.2s;
}
.gal-search:focus-within { border-color: var(--amber); box-shadow: 0 0 0 3px var(--amber-xs); }
.gal-search input {
  border: none; background: transparent; outline: none;
  font-family: 'DM Sans', sans-serif; font-size: 0.875rem;
  color: var(--text); width: 100%;
}
.gal-search input::placeholder { color: var(--dim); }
.gal-search-icon { color: var(--muted); font-size: 1rem; flex-shrink: 0; }
.gal-sort {
  background: var(--card); border: 1.5px solid var(--border);
  border-radius: 50px; padding: 10px 16px;
  font-family: 'DM Sans', sans-serif; font-size: 0.85rem;
  font-weight: 500; color: var(--text); cursor: pointer; outline: none;
  transition: 0.2s;
}
.gal-sort:focus { border-color: var(--amber); }
.gal-view-btns { display: flex; gap: 6px; }
.gal-vbtn {
  width: 38px; height: 38px; border-radius: 50%;
  border: 1.5px solid var(--border); background: transparent;
  cursor: pointer; font-size: 15px;
  display: flex; align-items: center; justify-content: center;
  transition: 0.2s; color: var(--muted);
}
.gal-vbtn:hover, .gal-vbtn.on { background: var(--amber-xs); border-color: var(--amber); color: var(--amber-l); }

/* ── CATEGORY CHIPS ── */
.gal-cats {
  max-width: 1140px; margin: 18px auto 0;
  padding: 0 24px; display: flex; gap: 8px; flex-wrap: wrap;
}
.gal-cat {
  padding: 9px 20px; border-radius: 50px;
  border: 1.5px solid var(--border);
  background: var(--surface); color: var(--muted);
  font-family: 'DM Sans', sans-serif; font-size: 0.82rem;
  font-weight: 600; cursor: pointer; transition: 0.2s;
  display: flex; align-items: center; gap: 7px;
}
.gal-cat:hover { border-color: var(--amber); color: var(--amber-l); }
.gal-cat.on {
  background: var(--amber); border-color: var(--amber);
  color: white; box-shadow: 0 4px 16px rgba(200,134,26,0.3);
}
.gal-cat-cnt {
  font-size: 0.68rem; padding: 2px 8px; border-radius: 50px;
  background: rgba(255,255,255,0.15);
}
.gal-cat:not(.on) .gal-cat-cnt { background: rgba(200,134,26,0.12); color: var(--amber); }

/* ── INFO ROW ── */
.gal-info {
  max-width: 1140px; margin: 14px auto 0;
  padding: 0 24px;
  display: flex; justify-content: space-between; align-items: center;
}
.gal-info-txt { font-size: 0.82rem; color: var(--muted); }
.gal-info-txt strong { color: var(--text); font-weight: 600; }
.gal-clear {
  font-size: 0.78rem; color: var(--amber);
  cursor: pointer; font-weight: 600;
  background: none; border: none;
  font-family: 'DM Sans', sans-serif; transition: color 0.2s;
}
.gal-clear:hover { color: var(--amber-l); }

/* ── GRID ── */
.gal-grid {
  max-width: 1140px; margin: 22px auto 0;
  padding: 0 24px 100px;
  display: grid; gap: 22px;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
}
.gal-grid.lv { grid-template-columns: 1fr; }

/* ── CARD ── */
.gal-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 24px; overflow: hidden;
  cursor: pointer; position: relative;
  box-shadow: 0 4px 24px rgba(0,0,0,0.3);
  transition: transform 0.35s cubic-bezier(.34,1.56,.64,1), box-shadow 0.35s ease, border-color 0.3s;
  animation: fadeUp 0.45s ease both;
}
.gal-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 24px 60px rgba(200,134,26,0.18);
  border-color: rgba(200,134,26,0.45);
}
.gal-card.lv {
  display: grid; grid-template-columns: 240px 1fr;
}
.gal-card.lv:hover { transform: translateY(-5px); }

/* IMG WRAP */
.gal-img-wrap {
  position: relative; overflow: hidden;
  aspect-ratio: 4/3; background: var(--card2);
}
.gal-card.lv .gal-img-wrap { aspect-ratio: unset; min-height: 200px; }
.gal-img {
  width: 100%; height: 100%; object-fit: cover; display: block;
  transition: transform 0.5s ease;
}
.gal-card:hover .gal-img { transform: scale(1.07); }

/* BADGES */
.gal-badge {
  position: absolute; top: 12px; left: 12px;
  padding: 4px 12px; border-radius: 50px;
  font-size: 0.65rem; font-weight: 700;
  letter-spacing: 0.1em; text-transform: uppercase; color: #fff;
}
.bp  { background: var(--amber); }
.bn  { background: var(--green); }
.bpr { background: var(--purple); }
.bv  { background: #3b82f6; }

/* WISHLIST BTN */
.gal-wish {
  position: absolute; top: 12px; right: 12px;
  width: 36px; height: 36px; border-radius: 50%;
  background: rgba(13,8,0,0.7); backdrop-filter: blur(6px);
  border: 1px solid var(--border); cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  font-size: 1rem; transition: 0.25s;
  opacity: 0; transform: scale(0.7);
}
.gal-card:hover .gal-wish,
.gal-wish.on { opacity: 1; transform: scale(1); }
.gal-wish:hover { transform: scale(1.2) !important; background: rgba(200,134,26,0.5); }

/* QUICK VIEW */
.gal-qv {
  position: absolute; bottom: 12px; left: 50%;
  transform: translateX(-50%) translateY(10px);
  background: rgba(13,8,0,0.88); backdrop-filter: blur(8px);
  border: 1px solid var(--border); border-radius: 50px;
  padding: 7px 18px; font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem; font-weight: 600; color: var(--amber-l);
  cursor: pointer; white-space: nowrap;
  opacity: 0; transition: 0.25s;
}
.gal-card:hover .gal-qv { opacity: 1; transform: translateX(-50%) translateY(0); }

/* CARD BODY */
.gal-body { padding: 18px 20px 20px; }
.gal-card.lv .gal-body { padding: 22px 26px; display: flex; flex-direction: column; justify-content: center; }

.gal-cat-tag {
  font-size: 0.68rem; font-weight: 700;
  letter-spacing: 0.16em; text-transform: uppercase;
  color: var(--amber); margin-bottom: 6px;
  display: flex; align-items: center; gap: 5px;
}
.gal-cat-tag::before {
  content: ''; display: inline-block;
  width: 5px; height: 5px; border-radius: 50%;
  background: var(--amber-l);
}
.gal-pname {
  font-family: 'Playfair Display', serif;
  font-size: 1.2rem; font-weight: 700;
  color: var(--text); margin: 0 0 3px; line-height: 1.2;
}
.gal-card.lv .gal-pname { font-size: 1.5rem; }
.gal-age { font-size: 0.75rem; color: var(--muted); margin-bottom: 6px; }
.gal-desc {
  font-size: 0.8rem; color: var(--dim);
  line-height: 1.65; margin-bottom: 10px; display: none;
}
.gal-card.lv .gal-desc { display: block; color: var(--muted); }

.gal-rat { display: flex; align-items: center; gap: 5px; margin-bottom: 14px; }
.gal-stars { color: var(--amber-l); font-size: 0.78rem; letter-spacing: 1px; }
.gal-revs  { font-size: 0.7rem; color: var(--dim); }

.gal-price-row {
  display: flex; align-items: center;
  justify-content: space-between; gap: 8px;
}
.gal-price {
  font-family: 'Playfair Display', serif;
  font-size: 1.5rem; font-weight: 700;
  color: var(--amber-l); line-height: 1;
}
.gal-price sup { font-family: 'DM Sans', sans-serif; font-size: 0.85rem; font-weight: 500; color: var(--muted); }

.gal-btns { display: flex; gap: 7px; align-items: center; }
.gal-cart-btn {
  padding: 8px 16px; border-radius: 50px; border: none;
  background: var(--amber); color: #fff;
  font-family: 'DM Sans', sans-serif; font-size: 0.75rem;
  font-weight: 700; cursor: pointer; transition: 0.22s;
  white-space: nowrap; display: flex; align-items: center; gap: 5px;
  box-shadow: 0 4px 14px rgba(200,134,26,0.3);
}
.gal-cart-btn:hover { background: #a06010; }
.gal-cart-btn.ok { background: var(--green); }

.gal-wa-btn {
  width: 36px; height: 36px; border-radius: 50%;
  border: 1.5px solid var(--border);
  background: var(--amber-xs); cursor: pointer;
  font-size: 14px; transition: 0.2s;
  display: flex; align-items: center; justify-content: center; flex-shrink: 0;
}
.gal-wa-btn:hover { border-color: var(--amber); transform: scale(1.1); }

/* ── SKELETON ── */
.gal-skel {
  background: var(--card); border: 1px solid var(--border);
  border-radius: 24px; overflow: hidden;
}
.gal-skel-img {
  height: 195px;
  background: linear-gradient(90deg, var(--card2) 25%, var(--surface) 50%, var(--card2) 75%);
  background-size: 200%; animation: shimmer 1.5s ease infinite;
}
.gal-skel-body { padding: 18px; }
.gal-skel-line {
  height: 11px; border-radius: 6px; margin-bottom: 10px;
  background: linear-gradient(90deg, var(--card2) 25%, var(--surface) 50%, var(--card2) 75%);
  background-size: 200%; animation: shimmer 1.5s ease infinite;
}
.gal-skel-line.w70 { width: 70%; }
.gal-skel-line.w50 { width: 50%; }

/* ── EMPTY ── */
.gal-empty {
  grid-column: 1 / -1; text-align: center; padding: 80px 20px;
}
.gal-empty-icon { font-size: 64px; display: block; margin-bottom: 16px; }
.gal-empty h3 {
  font-family: 'Playfair Display', serif;
  font-size: 1.5rem; font-weight: 700; color: var(--text); margin-bottom: 8px;
}
.gal-empty p { font-size: 0.875rem; color: var(--muted); }

/* ── MODAL ── */
.gal-modal-bg {
  position: fixed; inset: 0;
  background: rgba(5, 3, 0, 0.85);
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
  padding: 20px; backdrop-filter: blur(10px);
  animation: fadeUp 0.2s ease;
}
.gal-modal {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 28px; max-width: 680px;
  width: 100%; max-height: 90vh;
  overflow-y: auto; position: relative;
  box-shadow: 0 40px 100px rgba(0,0,0,0.6);
  animation: scaleIn 0.3s cubic-bezier(.22,1,.36,1);
}
.gal-modal-img {
  width: 100%; height: 280px;
  object-fit: cover; display: block;
  border-radius: 28px 28px 0 0;
}
.gal-modal-close {
  position: absolute; top: 14px; right: 14px;
  width: 38px; height: 38px; border-radius: 50%;
  background: rgba(13,8,0,0.75); backdrop-filter: blur(8px);
  border: 1px solid var(--border); font-size: 16px;
  cursor: pointer; display: flex; align-items: center; justify-content: center;
  color: var(--text); transition: 0.22s;
}
.gal-modal-close:hover { transform: rotate(90deg); background: var(--amber-xs); }

.gal-modal-body { padding: 26px 30px 32px; }
.gal-modal-name {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 700;
  color: var(--text); margin: 0 0 6px;
}
.gal-modal-price {
  font-family: 'Playfair Display', serif;
  font-size: 1.9rem; font-weight: 700;
  color: var(--amber-l); margin: 0 0 20px;
}
.gal-modal-feats {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 10px; margin-bottom: 22px;
}
.gal-feat {
  background: var(--card); border: 1px solid var(--border);
  border-radius: 14px; padding: 12px 14px;
  font-size: 0.82rem; color: var(--muted);
}
.gal-feat strong {
  display: block; font-size: 0.8rem;
  font-weight: 700; color: var(--text); margin-bottom: 2px;
}
.gal-modal-acts { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 12px; }
.gal-modal-cart {
  flex: 1; min-width: 140px;
  padding: 13px 20px; background: var(--amber); color: #fff;
  border: none; border-radius: 50px;
  font-family: 'DM Sans', sans-serif; font-size: 0.9rem;
  font-weight: 700; cursor: pointer;
  display: flex; align-items: center; justify-content: center; gap: 8px;
  box-shadow: 0 6px 20px rgba(200,134,26,0.35); transition: 0.22s;
}
.gal-modal-cart:hover { background: #a06010; }
.gal-modal-wa {
  padding: 13px 22px; border-radius: 50px;
  border: 1.5px solid var(--border); background: var(--amber-xs);
  font-family: 'DM Sans', sans-serif; font-size: 0.9rem;
  font-weight: 600; color: var(--amber-l); cursor: pointer;
  display: flex; align-items: center; gap: 7px; transition: 0.22s;
}
.gal-modal-wa:hover { background: var(--amber); color: white; border-color: var(--amber); }
.gal-modal-wl {
  padding: 12px 14px; border-radius: 50px;
  border: 1.5px solid var(--border); background: transparent;
  font-size: 18px; cursor: pointer; transition: 0.22s;
}
.gal-modal-wl:hover { background: var(--amber-xs); }
.gal-buy-now {
  width: 100%; padding: 14px;
  background: linear-gradient(135deg, var(--amber), #8b5000);
  color: #fff; border: none; border-radius: 50px;
  font-family: 'DM Sans', sans-serif; font-size: 0.95rem;
  font-weight: 700; cursor: pointer; transition: 0.22s;
  display: flex; align-items: center; justify-content: center; gap: 8px;
  box-shadow: 0 6px 24px rgba(200,134,26,0.35);
}
.gal-buy-now:hover { opacity: 0.88; transform: translateY(-2px); }

/* ── TOAST ── */
.gal-toast {
  position: fixed; bottom: 26px; right: 26px; z-index: 99999;
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text); border-radius: 50px;
  padding: 13px 22px; font-size: 0.875rem; font-weight: 500;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4);
  display: flex; align-items: center; gap: 10px;
  transform: translateY(80px); opacity: 0;
  transition: all 0.35s cubic-bezier(.34,1.46,.64,1);
  font-family: 'DM Sans', sans-serif;
  pointer-events: none;
}
.gal-toast.on { transform: translateY(0); opacity: 1; }

/* ── RESPONSIVE ── */
@media (max-width: 900px) {
  .gal-grid { grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); }
  .gal-card.lv { grid-template-columns: 1fr; }
  .gal-card.lv .gal-img-wrap { aspect-ratio: 4/3; min-height: unset; }
}
@media (max-width: 640px) {
  .gal-hero { padding: 60px 16px 80px; }
  .gal-hero-stats { gap: 24px; }
  .gal-grid { grid-template-columns: repeat(auto-fill, minmax(155px, 1fr)); gap: 14px; }
  .gal-modal-feats { grid-template-columns: 1fr; }
  .gal-modal-body { padding: 18px 16px 24px; }
  .gal-modal-name { font-size: 1.5rem; }
}
