import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

/* ════════════════════════════════════════════════════════════
   NAV — safe import
════════════════════════════════════════════════════════════ */
let Nav = () => null;
try { Nav = require("./Nev").default; } catch (e) {}

/* ════════════════════════════════════════════════════════════
   CONSTANTS
════════════════════════════════════════════════════════════ */
const WHATSAPP = "919999999999";
const API      = "http://localhost/Petshop/show.php";

const FALLBACK_IMGS = [
  "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=500&q=80",
  "https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=500&q=80",
  "https://images.unsplash.com/photo-1537151608828-ea2b11777ee8?w=500&q=80",
  "https://images.unsplash.com/photo-1583511655857-d19b40a7a54e?w=500&q=80",
  "https://images.unsplash.com/photo-1601979031925-424e53b6caaa?w=500&q=80",
  "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=500&q=80",
  "https://images.unsplash.com/photo-1574158622682-e40e69881006?w=500&q=80",
  "https://images.unsplash.com/photo-1552728089-57bdde30beb3?w=500&q=80",
  "https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=500&q=80",
  "https://images.unsplash.com/photo-1615789591457-74a63395c990?w=500&q=80",
];

const DEMO_PETS = [
  { id:"1", pname:"Affenpinscher",    price:10000,  cat:"Dogs",  age:"8 weeks",  rating:4.8, reviews:124, badge:{label:"POPULAR",  cls:"bp"}, img: FALLBACK_IMGS[0], desc:"Curious, lively & fearless apartment companion." },
  { id:"2", pname:"Alaskan Husky",    price:20000,  cat:"Dogs",  age:"10 weeks", rating:4.6, reviews:89,  badge:{label:"NEW",       cls:"bn"}, img: FALLBACK_IMGS[1], desc:"Energetic sled breed that thrives outdoors." },
  { id:"3", pname:"Golden Retriever", price:35000,  cat:"Dogs",  age:"3 months", rating:4.9, reviews:203, badge:{label:"PREMIUM",   cls:"bpr"},img: FALLBACK_IMGS[5], desc:"Loyal, friendly & great with kids." },
  { id:"4", pname:"Airedale Terrier", price:400000, cat:"Dogs",  age:"2 months", rating:4.7, reviews:156, badge:{label:"VERIFIED",  cls:"bv"}, img: FALLBACK_IMGS[3], desc:"King of terriers — intelligent & confident." },
  { id:"5", pname:"Labrador",         price:18000,  cat:"Dogs",  age:"12 weeks", rating:4.5, reviews:67,  badge:{label:"POPULAR",   cls:"bp"}, img: FALLBACK_IMGS[4], desc:"Playful, obedient & great family dog." },
  { id:"6", pname:"Persian Cat",      price:15000,  cat:"Cats",  age:"8 weeks",  rating:4.8, reviews:178, badge:{label:"POPULAR",   cls:"bp"}, img: FALLBACK_IMGS[6], desc:"Silky fur, calm & loving indoor companion." },
  { id:"7", pname:"Maine Coon",       price:25000,  cat:"Cats",  age:"10 weeks", rating:4.7, reviews:134, badge:{label:"PREMIUM",   cls:"bpr"},img: FALLBACK_IMGS[9], desc:"Gentle giant — affectionate & playful." },
  { id:"8", pname:"Siamese",          price:12000,  cat:"Cats",  age:"3 months", rating:4.6, reviews:91,  badge:{label:"NEW",       cls:"bn"}, img: FALLBACK_IMGS[6], desc:"Vocal, social & beautifully patterned." },
  { id:"9", pname:"African Grey",     price:35000,  cat:"Birds", age:"6 months", rating:4.9, reviews:212, badge:{label:"PREMIUM",   cls:"bpr"},img: FALLBACK_IMGS[7], desc:"Smartest talking parrot in the world." },
  { id:"10",pname:"Cockatiel",        price:5000,   cat:"Birds", age:"8 weeks",  rating:4.6, reviews:87,  badge:{label:"POPULAR",   cls:"bp"}, img: FALLBACK_IMGS[7], desc:"Friendly, melodious & easy to train." },
  { id:"11",pname:"Macaw",            price:120000, cat:"Birds", age:"4 months", rating:4.8, reviews:145, badge:{label:"VERIFIED",  cls:"bv"}, img: FALLBACK_IMGS[7], desc:"Majestic, colourful & highly intelligent." },
  { id:"12",pname:"Arowana",          price:50000,  cat:"Fish",  age:"6 months", rating:4.9, reviews:198, badge:{label:"PREMIUM",   cls:"bpr"},img: FALLBACK_IMGS[8], desc:"The lucky dragon fish — rare & majestic." },
  { id:"13",pname:"Betta Fish",       price:500,    cat:"Fish",  age:"3 months", rating:4.7, reviews:312, badge:{label:"POPULAR",   cls:"bp"}, img: FALLBACK_IMGS[8], desc:"Stunning colours, very easy to care for." },
  { id:"14",pname:"Koi Fish",         price:10000,  cat:"Fish",  age:"1 year",   rating:4.8, reviews:156, badge:{label:"NEW",       cls:"bn"}, img: FALLBACK_IMGS[8], desc:"Graceful pond beauty, symbol of luck." },
];

const CATEGORIES  = ["All","Dogs","Cats","Birds","Fish"];
const CAT_ICONS   = { All:"🐾", Dogs:"🐕", Cats:"🐈", Birds:"🦜", Fish:"🐠" };

const starsStr = (r) => {
  const f = Math.floor(r || 0);
  return "★".repeat(f) + "☆".repeat(Math.max(0, 5 - f));
};

/* ════════════════════════════════════════════════════════════
   STYLES
════════════════════════════════════════════════════════════ */
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,900;1,700&family=DM+Sans:wght@300;400;500;600;700&display=swap');

:root {
  --bg:       #0d0800;
  --surface:  #170e00;
  --card:     #1f1400;
  --card2:    #261a00;
  --amber:    #c8861a;
  --amber-l:  #e8a840;
  --amber-xs: rgba(200,134,26,0.12);
  --border:   rgba(200,134,26,0.16);
  --text:     #f0e0c0;
  --muted:    #9a7a55;
  --dim:      #5a4030;
  --white:    #ffffff;
  --green:    #10b981;
  --purple:   #8b5cf6;
  --red:      #ef4444;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }

body {
  font-family: 'DM Sans', sans-serif;
  background: var(--bg);
  color: var(--text);
  overflow-x: hidden;
  min-height: 100vh;
}

::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--amber); border-radius: 10px; }

/* ── ANIMATIONS ── */
@keyframes fadeUp    { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }
@keyframes shimmer   { 0%{background-position:200% 0} 100%{background-position:-200% 0} }
@keyframes orbDrift  { 0%,100%{transform:translate(0,0) scale(1)} 40%{transform:translate(40px,-30px) scale(1.08)} 70%{transform:translate(-20px,20px) scale(.96)} }
@keyframes blink     { 0%,100%{opacity:1} 50%{opacity:0.2} }
@keyframes scaleIn   { from{opacity:0;transform:scale(0.92)} to{opacity:1;transform:scale(1)} }

/* ── GALLERY PAGE ROOT ── */
.gal-root {
  min-height: 100vh;
  background: var(--bg);
  font-family: 'DM Sans', sans-serif;
  color: var(--text);
}

/* ── HERO ── */
.gal-hero {
  background: linear-gradient(160deg, #0d0500, #261200, #130800);
  padding: 80px 24px 100px;
  text-align: center;
  position: relative;
  overflow: hidden;
}
.gal-orb {
  position: absolute; border-radius: 50%;
  filter: blur(80px); opacity: 0.2;
  pointer-events: none; animation: orbDrift 14s ease-in-out infinite;
}
.gal-orb1 { width:450px;height:450px; background:radial-gradient(circle,#c8861a,transparent 70%); top:-120px;left:-80px; }
.gal-orb2 { width:350px;height:350px; background:radial-gradient(circle,#4a7a4a,transparent 70%); bottom:-80px;right:-60px; animation-delay:-7s; }
.gal-hero-wave {
  position: absolute; bottom: 0; left: 0; right: 0; height: 60px;
  background: var(--bg);
  clip-path: ellipse(58% 100% at 50% 100%);
}
.gal-hero-inner {
  position: relative; z-index: 2;
  max-width: 760px; margin: 0 auto;
}
.gal-pill {
  display: inline-flex; align-items: center; gap: 8px;
  background: rgba(200,134,26,0.12);
  border: 1px solid rgba(200,134,26,0.3);
  color: var(--amber-l);
  font-size: 0.72rem; font-weight: 700;
  letter-spacing: 0.18em; text-transform: uppercase;
  padding: 7px 20px; border-radius: 50px; margin-bottom: 24px;
}
.gal-dot { width:6px;height:6px; background:var(--amber-l); border-radius:50%; animation:blink 1.5s infinite; }
.gal-hero-inner h1 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(2.5rem, 5.5vw, 5rem);
  font-weight: 900; line-height: 1.08;
  color: var(--white); margin-bottom: 16px;
}
.gal-hero-inner h1 em { font-style: italic; color: var(--amber-l); }
.gal-hero-inner p {
  color: rgba(255,255,255,0.5);
  font-size: 1rem; font-weight: 300;
  max-width: 500px; margin: 0 auto 36px; line-height: 1.8;
}
.gal-hero-stats {
  display: flex; justify-content: center; gap: 48px; flex-wrap: wrap;
}
.gal-stat-num {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 700;
  color: var(--amber-l); display: block;
}
.gal-stat-lbl {
  font-size: 0.68rem; color: rgba(255,255,255,0.35);
  letter-spacing: 0.18em; text-transform: uppercase;
}

/* ── SEARCH BAR ── */
.gal-bar {
  max-width: 1140px; margin: -28px auto 0;
  padding: 0 24px; position: relative; z-index: 10;
}
.gal-bar-inner {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 20px; padding: 18px 22px;
  box-shadow: 0 12px 48px rgba(0,0,0,0.4);
  display: flex; gap: 12px; align-items: center; flex-wrap: wrap;
}
.gal-search {
  flex: 1; min-width: 180px;
  display: flex; align-items: center; gap: 10px;
  background: var(--card); border: 1.5px solid var(--border);
  border-radius: 50px; padding: 10px 18px; transition: 0.2s;
}
.gal-search:focus-within { border-color: var(--amber); box-shadow: 0 0 0 3px var(--amber-xs); }
.gal-search input {
  border: none; background: transparent; outline: none;
  font-family: 'DM Sans', sans-serif; font-size: 0.875rem;
  color: var(--text); width: 100%;
}
.gal-search input::placeholder { color: var(--dim); }
.gal-search-icon { color: var(--muted); font-size: 1rem; flex-shrink: 0; }
.gal-sort {
  background: var(--card); border: 1.5px solid var(--border);
  border-radius: 50px; padding: 10px 16px;
  font-family: 'DM Sans', sans-serif; font-size: 0.85rem;
  font-weight: 500; color: var(--text); cursor: pointer; outline: none;
  transition: 0.2s;
}
.gal-sort:focus { border-color: var(--amber); }
.gal-view-btns { display: flex; gap: 6px; }
.gal-vbtn {
  width: 38px; height: 38px; border-radius: 50%;
  border: 1.5px solid var(--border); background: transparent;
  cursor: pointer; font-size: 15px;
  display: flex; align-items: center; justify-content: center;
  transition: 0.2s; color: var(--muted);
}
.gal-vbtn:hover, .gal-vbtn.on { background: var(--amber-xs); border-color: var(--amber); color: var(--amber-l); }

/* ── CATEGORY CHIPS ── */
.gal-cats {
  max-width: 1140px; margin: 18px auto 0;
  padding: 0 24px; display: flex; gap: 8px; flex-wrap: wrap;
}
.gal-cat {
  padding: 9px 20px; border-radius: 50px;
  border: 1.5px solid var(--border);
  background: var(--surface); color: var(--muted);
  font-family: 'DM Sans', sans-serif; font-size: 0.82rem;
  font-weight: 600; cursor: pointer; transition: 0.2s;
  display: flex; align-items: center; gap: 7px;
}
.gal-cat:hover { border-color: var(--amber); color: var(--amber-l); }
.gal-cat.on {
  background: var(--amber); border-color: var(--amber);
  color: white; box-shadow: 0 4px 16px rgba(200,134,26,0.3);
}
.gal-cat-cnt {
  font-size: 0.68rem; padding: 2px 8px; border-radius: 50px;
  background: rgba(255,255,255,0.15);
}
.gal-cat:not(.on) .gal-cat-cnt { background: rgba(200,134,26,0.12); color: var(--amber); }

/* ── INFO ROW ── */
.gal-info {
  max-width: 1140px; margin: 14px auto 0;
  padding: 0 24px;
  display: flex; justify-content: space-between; align-items: center;
}
.gal-info-txt { font-size: 0.82rem; color: var(--muted); }
.gal-info-txt strong { color: var(--text); font-weight: 600; }
.gal-clear {
  font-size: 0.78rem; color: var(--amber);
  cursor: pointer; font-weight: 600;
  background: none; border: none;
  font-family: 'DM Sans', sans-serif; transition: color 0.2s;
}
.gal-clear:hover { color: var(--amber-l); }

/* ── GRID ── */
.gal-grid {
  max-width: 1140px; margin: 22px auto 0;
  padding: 0 24px 100px;
  display: grid; gap: 22px;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
}
.gal-grid.lv { grid-template-columns: 1fr; }

/* ── CARD ── */
.gal-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 24px; overflow: hidden;
  cursor: pointer; position: relative;
  box-shadow: 0 4px 24px rgba(0,0,0,0.3);
  transition: transform 0.35s cubic-bezier(.34,1.56,.64,1), box-shadow 0.35s ease, border-color 0.3s;
  animation: fadeUp 0.45s ease both;
}
.gal-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 24px 60px rgba(200,134,26,0.18);
  border-color: rgba(200,134,26,0.45);
}
.gal-card.lv {
  display: grid; grid-template-columns: 240px 1fr;
}
.gal-card.lv:hover { transform: translateY(-5px); }

/* IMG WRAP */
.gal-img-wrap {
  position: relative; overflow: hidden;
  aspect-ratio: 4/3; background: var(--card2);
}
.gal-card.lv .gal-img-wrap { aspect-ratio: unset; min-height: 200px; }
.gal-img {
  width: 100%; height: 100%; object-fit: cover; display: block;
  transition: transform 0.5s ease;
}
.gal-card:hover .gal-img { transform: scale(1.07); }

/* BADGES */
.gal-badge {
  position: absolute; top: 12px; left: 12px;
  padding: 4px 12px; border-radius: 50px;
  font-size: 0.65rem; font-weight: 700;
  letter-spacing: 0.1em; text-transform: uppercase; color: #fff;
}
.bp  { background: var(--amber); }
.bn  { background: var(--green); }
.bpr { background: var(--purple); }
.bv  { background: #3b82f6; }

/* WISHLIST BTN */
.gal-wish {
  position: absolute; top: 12px; right: 12px;
  width: 36px; height: 36px; border-radius: 50%;
  background: rgba(13,8,0,0.7); backdrop-filter: blur(6px);
  border: 1px solid var(--border); cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  font-size: 1rem; transition: 0.25s;
  opacity: 0; transform: scale(0.7);
}
.gal-card:hover .gal-wish,
.gal-wish.on { opacity: 1; transform: scale(1); }
.gal-wish:hover { transform: scale(1.2) !important; background: rgba(200,134,26,0.5); }

/* QUICK VIEW */
.gal-qv {
  position: absolute; bottom: 12px; left: 50%;
  transform: translateX(-50%) translateY(10px);
  background: rgba(13,8,0,0.88); backdrop-filter: blur(8px);
  border: 1px solid var(--border); border-radius: 50px;
  padding: 7px 18px; font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem; font-weight: 600; color: var(--amber-l);
  cursor: pointer; white-space: nowrap;
  opacity: 0; transition: 0.25s;
}
.gal-card:hover .gal-qv { opacity: 1; transform: translateX(-50%) translateY(0); }

/* CARD BODY */
.gal-body { padding: 18px 20px 20px; }
.gal-card.lv .gal-body { padding: 22px 26px; display: flex; flex-direction: column; justify-content: center; }

.gal-cat-tag {
  font-size: 0.68rem; font-weight: 700;
  letter-spacing: 0.16em; text-transform: uppercase;
  color: var(--amber); margin-bottom: 6px;
  display: flex; align-items: center; gap: 5px;
}
.gal-cat-tag::before {
  content: ''; display: inline-block;
  width: 5px; height: 5px; border-radius: 50%;
  background: var(--amber-l);
}
.gal-pname {
  font-family: 'Playfair Display', serif;
  font-size: 1.2rem; font-weight: 700;
  color: var(--text); margin: 0 0 3px; line-height: 1.2;
}
.gal-card.lv .gal-pname { font-size: 1.5rem; }
.gal-age { font-size: 0.75rem; color: var(--muted); margin-bottom: 6px; }
.gal-desc {
  font-size: 0.8rem; color: var(--dim);
  line-height: 1.65; margin-bottom: 10px; display: none;
}
.gal-card.lv .gal-desc { display: block; color: var(--muted); }

.gal-rat { display: flex; align-items: center; gap: 5px; margin-bottom: 14px; }
.gal-stars { color: var(--amber-l); font-size: 0.78rem; letter-spacing: 1px; }
.gal-revs  { font-size: 0.7rem; color: var(--dim); }

.gal-price-row {
  display: flex; align-items: center;
  justify-content: space-between; gap: 8px;
}
.gal-price {
  font-family: 'Playfair Display', serif;
  font-size: 1.5rem; font-weight: 700;
  color: var(--amber-l); line-height: 1;
}
.gal-price sup { font-family: 'DM Sans', sans-serif; font-size: 0.85rem; font-weight: 500; color: var(--muted); }

.gal-btns { display: flex; gap: 7px; align-items: center; }
.gal-cart-btn {
  padding: 8px 16px; border-radius: 50px; border: none;
  background: var(--amber); color: #fff;
  font-family: 'DM Sans', sans-serif; font-size: 0.75rem;
  font-weight: 700; cursor: pointer; transition: 0.22s;
  white-space: nowrap; display: flex; align-items: center; gap: 5px;
  box-shadow: 0 4px 14px rgba(200,134,26,0.3);
}
.gal-cart-btn:hover { background: #a06010; }
.gal-cart-btn.ok { background: var(--green); }

.gal-wa-btn {
  width: 36px; height: 36px; border-radius: 50%;
  border: 1.5px solid var(--border);
  background: var(--amber-xs); cursor: pointer;
  font-size: 14px; transition: 0.2s;
  display: flex; align-items: center; justify-content: center; flex-shrink: 0;
}
.gal-wa-btn:hover { border-color: var(--amber); transform: scale(1.1); }

/* ── SKELETON ── */
.gal-skel {
  background: var(--card); border: 1px solid var(--border);
  border-radius: 24px; overflow: hidden;
}
.gal-skel-img {
  height: 195px;
  background: linear-gradient(90deg, var(--card2) 25%, var(--surface) 50%, var(--card2) 75%);
  background-size: 200%; animation: shimmer 1.5s ease infinite;
}
.gal-skel-body { padding: 18px; }
.gal-skel-line {
  height: 11px; border-radius: 6px; margin-bottom: 10px;
  background: linear-gradient(90deg, var(--card2) 25%, var(--surface) 50%, var(--card2) 75%);
  background-size: 200%; animation: shimmer 1.5s ease infinite;
}
.gal-skel-line.w70 { width: 70%; }
.gal-skel-line.w50 { width: 50%; }

/* ── EMPTY ── */
.gal-empty {
  grid-column: 1 / -1; text-align: center; padding: 80px 20px;
}
.gal-empty-icon { font-size: 64px; display: block; margin-bottom: 16px; }
.gal-empty h3 {
  font-family: 'Playfair Display', serif;
  font-size: 1.5rem; font-weight: 700; color: var(--text); margin-bottom: 8px;
}
.gal-empty p { font-size: 0.875rem; color: var(--muted); }

/* ── MODAL ── */
.gal-modal-bg {
  position: fixed; inset: 0;
  background: rgba(5, 3, 0, 0.85);
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
  padding: 20px; backdrop-filter: blur(10px);
  animation: fadeUp 0.2s ease;
}
.gal-modal {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 28px; max-width: 680px;
  width: 100%; max-height: 90vh;
  overflow-y: auto; position: relative;
  box-shadow: 0 40px 100px rgba(0,0,0,0.6);
  animation: scaleIn 0.3s cubic-bezier(.22,1,.36,1);
}
.gal-modal-img {
  width: 100%; height: 280px;
  object-fit: cover; display: block;
  border-radius: 28px 28px 0 0;
}
.gal-modal-close {
  position: absolute; top: 14px; right: 14px;
  width: 38px; height: 38px; border-radius: 50%;
  background: rgba(13,8,0,0.75); backdrop-filter: blur(8px);
  border: 1px solid var(--border); font-size: 16px;
  cursor: pointer; display: flex; align-items: center; justify-content: center;
  color: var(--text); transition: 0.22s;
}
.gal-modal-close:hover { transform: rotate(90deg); background: var(--amber-xs); }

.gal-modal-body { padding: 26px 30px 32px; }
.gal-modal-name {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 700;
  color: var(--text); margin: 0 0 6px;
}
.gal-modal-price {
  font-family: 'Playfair Display', serif;
  font-size: 1.9rem; font-weight: 700;
  color: var(--amber-l); margin: 0 0 20px;
}
.gal-modal-feats {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 10px; margin-bottom: 22px;
}
.gal-feat {
  background: var(--card); border: 1px solid var(--border);
  border-radius: 14px; padding: 12px 14px;
  font-size: 0.82rem; color: var(--muted);
}
.gal-feat strong {
  display: block; font-size: 0.8rem;
  font-weight: 700; color: var(--text); margin-bottom: 2px;
}
.gal-modal-acts { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 12px; }
.gal-modal-cart {
  flex: 1; min-width: 140px;
  padding: 13px 20px; background: var(--amber); color: #fff;
  border: none; border-radius: 50px;
  font-family: 'DM Sans', sans-serif; font-size: 0.9rem;
  font-weight: 700; cursor: pointer;
  display: flex; align-items: center; justify-content: center; gap: 8px;
  box-shadow: 0 6px 20px rgba(200,134,26,0.35); transition: 0.22s;
}
.gal-modal-cart:hover { background: #a06010; }
.gal-modal-wa {
  padding: 13px 22px; border-radius: 50px;
  border: 1.5px solid var(--border); background: var(--amber-xs);
  font-family: 'DM Sans', sans-serif; font-size: 0.9rem;
  font-weight: 600; color: var(--amber-l); cursor: pointer;
  display: flex; align-items: center; gap: 7px; transition: 0.22s;
}
.gal-modal-wa:hover { background: var(--amber); color: white; border-color: var(--amber); }
.gal-modal-wl {
  padding: 12px 14px; border-radius: 50px;
  border: 1.5px solid var(--border); background: transparent;
  font-size: 18px; cursor: pointer; transition: 0.22s;
}
.gal-modal-wl:hover { background: var(--amber-xs); }
.gal-buy-now {
  width: 100%; padding: 14px;
  background: linear-gradient(135deg, var(--amber), #8b5000);
  color: #fff; border: none; border-radius: 50px;
  font-family: 'DM Sans', sans-serif; font-size: 0.95rem;
  font-weight: 700; cursor: pointer; transition: 0.22s;
  display: flex; align-items: center; justify-content: center; gap: 8px;
  box-shadow: 0 6px 24px rgba(200,134,26,0.35);
}
.gal-buy-now:hover { opacity: 0.88; transform: translateY(-2px); }

/* ── TOAST ── */
.gal-toast {
  position: fixed; bottom: 26px; right: 26px; z-index: 99999;
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text); border-radius: 50px;
  padding: 13px 22px; font-size: 0.875rem; font-weight: 500;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4);
  display: flex; align-items: center; gap: 10px;
  transform: translateY(80px); opacity: 0;
  transition: all 0.35s cubic-bezier(.34,1.46,.64,1);
  font-family: 'DM Sans', sans-serif;
  pointer-events: none;
}
.gal-toast.on { transform: translateY(0); opacity: 1; }

/* ── RESPONSIVE ── */
@media (max-width: 900px) {
  .gal-grid { grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); }
  .gal-card.lv { grid-template-columns: 1fr; }
  .gal-card.lv .gal-img-wrap { aspect-ratio: 4/3; min-height: unset; }
}
@media (max-width: 640px) {
  .gal-hero { padding: 60px 16px 80px; }
  .gal-hero-stats { gap: 24px; }
  .gal-grid { grid-template-columns: repeat(auto-fill, minmax(155px, 1fr)); gap: 14px; }
  .gal-modal-feats { grid-template-columns: 1fr; }
  .gal-modal-body { padding: 18px 16px 24px; }
  .gal-modal-name { font-size: 1.5rem; }
}
`;

/* ════════════════════════════════════════════════════════════
   COMPONENT
════════════════════════════════════════════════════════════ */
export default function PetGallery() {
  // ── ALL HOOKS UNCONDITIONALLY AT TOP ──────────────────────
  const navigate = useNavigate();                        // ✅ always first, unconditional

  const [pets,    setPets]    = useState([]);
  const [loading, setLoading] = useState(true);
  const [search,  setSearch]  = useState("");
  const [cat,     setCat]     = useState("All");
  const [sort,    setSort]    = useState("default");
  const [view,    setView]    = useState("grid");
  const [wl,      setWl]      = useState([]);
  const [added,   setAdded]   = useState({});
  const [modal,   setModal]   = useState(null);
  const [toast,   setToast]   = useState({ on: false, msg: "" });

  // ── FETCH PETS ────────────────────────────────────────────
  useEffect(() => {
    let done = false;

    // Safety fallback — always show something after 3s
    const timer = setTimeout(() => {
      if (!done) { done = true; loadPets(DEMO_PETS); }
    }, 3000);

    fetch(API)
      .then(r => {
        if (!r.ok) throw new Error("not ok");
        return r.json();
      })
      .then(data => {
        if (done) return;
        done = true;
        clearTimeout(timer);
        const arr = Array.isArray(data) ? data.filter(p => p && p.pname) : [];
        loadPets(arr.length ? arr : DEMO_PETS);
      })
      .catch(() => {
        if (done) return;
        done = true;
        clearTimeout(timer);
        loadPets(DEMO_PETS);
      });

    return () => clearTimeout(timer);
  }, []);

  function loadPets(src) {
    const mapped = src.map((p, i) => ({
      id:      String(p.id || i + 1),
      pname:   p.pname   || "Unknown",
      price:   parseInt(p.price)  || 0,
      cat:     p.cat     || "Dogs",
      age:     p.age     || "8 weeks",
      rating:  p.rating  || parseFloat((4.5 + ((i * 7) % 5) / 10).toFixed(1)),
      reviews: p.reviews || (40 + ((i * 37) % 200)),
      badge:   p.badge   || [
        { label:"POPULAR", cls:"bp"  },
        { label:"NEW",     cls:"bn"  },
        { label:"PREMIUM", cls:"bpr" },
        { label:"VERIFIED",cls:"bv"  },
      ][i % 4],
      img:     (p.image && String(p.image).trim()) ? p.image : FALLBACK_IMGS[i % FALLBACK_IMGS.length],
      desc:    p.desc    || "A healthy, vaccinated companion ready for a loving home.",
    }));
    setPets(mapped);
    setLoading(false);
  }

  // ── HELPERS ───────────────────────────────────────────────
  const showToast = (msg) => {
    setToast({ on: true, msg });
    setTimeout(() => setToast({ on: false, msg: "" }), 3000);
  };

  const toggleWl = (id, e) => {
    if (e) e.stopPropagation();
    setWl(w => w.includes(id) ? w.filter(x => x !== id) : [...w, id]);
  };

  const addCart = (pet, e) => {
    if (e) e.stopPropagation();
    try {
      localStorage.setItem("item", pet.price);
      localStorage.setItem("pid",  pet.id);
    } catch (_) {}
    setAdded(a => ({ ...a, [pet.id]: true }));
    setTimeout(() => setAdded(a => ({ ...a, [pet.id]: false })), 1600);
    showToast("🛒 " + pet.pname + " added to cart!");
  };

  const buyNow = (pet) => {
    addCart(pet);
    setTimeout(() => navigate("/cart"), 350);
  };

  const waInquiry = (pet, e) => {
    if (e) e.stopPropagation();
    const msg = encodeURIComponent(
      "Hi! I'm interested in *" + pet.pname +
      "* listed at ₹" + pet.price.toLocaleString("en-IN") +
      ". Please share details."
    );
    window.open("https://wa.me/" + WHATSAPP + "?text=" + msg, "_blank");
  };

  // ── FILTER & SORT ─────────────────────────────────────────
  const filtered = pets
    .filter(p => cat === "All" || p.cat === cat)
    .filter(p => p.pname.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      if (sort === "price-asc")  return a.price - b.price;
      if (sort === "price-desc") return b.price - a.price;
      if (sort === "rating")     return b.rating - a.rating;
      if (sort === "name")       return a.pname.localeCompare(b.pname);
      return 0;
    });

  const catCount = (c) => c === "All"
    ? pets.length
    : pets.filter(p => p.cat === c).length;

  /* ══════════════════════════════════════════════════════════
     RENDER
  ══════════════════════════════════════════════════════════ */
  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />

      <div className="gal-root">
        <Nav />

        {/* ── HERO ── */}
        <div className="gal-hero">
          <div className="gal-orb gal-orb1" />
          <div className="gal-orb gal-orb2" />
          <div className="gal-hero-inner">
            <div className="gal-pill">
              <span className="gal-dot" />
              Premium Pet Marketplace
            </div>
            <h1>
              Find Your Perfect<br />
              <em>Companion</em>
            </h1>
            <p>
              Hand-picked, vaccinated & health-certified pets
              from trusted breeders across India.
            </p>
            <div className="gal-hero-stats">
              {[
                { num: pets.length ? pets.length + "+" : "50+", lbl: "Pets Available" },
                { num: "100%", lbl: "Health Verified" },
                { num: "4.9★", lbl: "Avg Rating" },
                { num: "Free", lbl: "Home Delivery" },
              ].map((s, i) => (
                <div key={i}>
                  <span className="gal-stat-num">{s.num}</span>
                  <span className="gal-stat-lbl">{s.lbl}</span>
                </div>
              ))}
            </div>
          </div>
          <div className="gal-hero-wave" />
        </div>

        {/* ── SEARCH BAR ── */}
        <div className="gal-bar">
          <div className="gal-bar-inner">
            <div className="gal-search">
              <span className="gal-search-icon">🔍</span>
              <input
                placeholder="Search breed..."
                value={search}
                onChange={e => setSearch(e.target.value)}
              />
            </div>
            <select
              className="gal-sort"
              value={sort}
              onChange={e => setSort(e.target.value)}
            >
              <option value="default">Featured</option>
              <option value="price-asc">Price: Low → High</option>
              <option value="price-desc">Price: High → Low</option>
              <option value="rating">Top Rated</option>
              <option value="name">A → Z</option>
            </select>
            <div className="gal-view-btns">
              <button className={"gal-vbtn" + (view === "grid" ? " on" : "")} onClick={() => setView("grid")} title="Grid">⊞</button>
              <button className={"gal-vbtn" + (view === "list" ? " on" : "")} onClick={() => setView("list")} title="List">☰</button>
            </div>
          </div>
        </div>

        {/* ── CATEGORY CHIPS ── */}
        <div className="gal-cats">
          {CATEGORIES.map(c => (
            <button
              key={c}
              className={"gal-cat" + (cat === c ? " on" : "")}
              onClick={() => setCat(c)}
            >
              {CAT_ICONS[c]} {c}
              <span className="gal-cat-cnt">{catCount(c)}</span>
            </button>
          ))}
        </div>

        {/* ── INFO ROW ── */}
        <div className="gal-info">
          <span className="gal-info-txt">
            Showing <strong>{filtered.length}</strong> of <strong>{pets.length}</strong> pets
            {search && <> for "<strong>{search}</strong>"</>}
          </span>
          {(search || cat !== "All") && (
            <button className="gal-clear" onClick={() => { setSearch(""); setCat("All"); }}>
              Clear filters ✕
            </button>
          )}
        </div>

        {/* ── PET GRID ── */}
        <div className={"gal-grid" + (view === "list" ? " lv" : "")}>
          {loading
            ? Array(8).fill(0).map((_, i) => (
                <div className="gal-skel" key={i}>
                  <div className="gal-skel-img" />
                  <div className="gal-skel-body">
                    <div className="gal-skel-line" />
                    <div className="gal-skel-line w70" />
                    <div className="gal-skel-line w50" />
                  </div>
                </div>
              ))
            : filtered.length === 0
            ? (
                <div className="gal-empty">
                  <span className="gal-empty-icon">🐾</span>
                  <h3>No pets found</h3>
                  <p>Try adjusting your search or category filters</p>
                </div>
              )
            : filtered.map((pet, i) => (
                <div
                  key={pet.id}
                  className={"gal-card" + (view === "list" ? " lv" : "")}
                  style={{ animationDelay: (i % 12) * 0.05 + "s" }}
                  onClick={() => setModal(pet)}
                >
                  {/* Image */}
                  <div className="gal-img-wrap">
                    <img
                      src={pet.img}
                      alt={pet.pname}
                      className="gal-img"
                      onError={e => {
                        e.target.onerror = null;
                        e.target.src = FALLBACK_IMGS[i % FALLBACK_IMGS.length];
                      }}
                    />
                    {pet.badge && (
                      <span className={"gal-badge " + pet.badge.cls}>
                        {pet.badge.label}
                      </span>
                    )}
                    <button
                      className={"gal-wish" + (wl.includes(pet.id) ? " on" : "")}
                      onClick={e => toggleWl(pet.id, e)}
                    >
                      {wl.includes(pet.id) ? "❤️" : "🤍"}
                    </button>
                    <button
                      className="gal-qv"
                      onClick={e => { e.stopPropagation(); setModal(pet); }}
                    >
                      Quick View →
                    </button>
                  </div>

                  {/* Body */}
                  <div className="gal-body">
                    <div className="gal-cat-tag">{pet.cat}</div>
                    <div className="gal-pname">{pet.pname}</div>
                    <div className="gal-age">🐣 {pet.age} old</div>
                    <div className="gal-desc">{pet.desc}</div>
                    <div className="gal-rat">
                      <span className="gal-stars">{starsStr(pet.rating)}</span>
                      <span className="gal-revs">({pet.reviews})</span>
                    </div>
                    <div className="gal-price-row">
                      <div className="gal-price">
                        <sup>₹</sup>{pet.price.toLocaleString("en-IN")}
                      </div>
                      <div className="gal-btns">
                        <button
                          className={"gal-cart-btn" + (added[pet.id] ? " ok" : "")}
                          onClick={e => addCart(pet, e)}
                        >
                          {added[pet.id] ? "✓ Added" : "🛒 Add"}
                        </button>
                        <button
                          className="gal-wa-btn"
                          title="WhatsApp Enquiry"
                          onClick={e => waInquiry(pet, e)}
                        >
                          💬
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))
          }
        </div>

        {/* ── MODAL ── */}
        {modal && (
          <div className="gal-modal-bg" onClick={() => setModal(null)}>
            <div className="gal-modal" onClick={e => e.stopPropagation()}>
              <img
                src={modal.img}
                alt={modal.pname}
                className="gal-modal-img"
                onError={e => { e.target.onerror = null; e.target.src = FALLBACK_IMGS[0]; }}
              />
              <button className="gal-modal-close" onClick={() => setModal(null)}>✕</button>
              <div className="gal-modal-body">
                <div className="gal-cat-tag" style={{ marginBottom: 8 }}>{modal.cat}</div>
                <div style={{ display:"flex", alignItems:"center", gap:10, flexWrap:"wrap", marginBottom:6 }}>
                  <div className="gal-modal-name">{modal.pname}</div>
                  {modal.badge && (
                    <span className={"gal-badge " + modal.badge.cls} style={{ position:"static" }}>
                      {modal.badge.label}
                    </span>
                  )}
                </div>
                <div className="gal-rat" style={{ marginBottom: 10 }}>
                  <span className="gal-stars">{starsStr(modal.rating)}</span>
                  <span className="gal-revs">({modal.reviews} reviews)</span>
                </div>
                <div className="gal-modal-price">₹{modal.price.toLocaleString("en-IN")}</div>
                <p style={{ fontSize:"0.875rem", color:"var(--muted)", lineHeight:1.75, marginBottom:20 }}>
                  {modal.desc} Comes with health certificate, vaccination record & 7-day health guarantee.
                </p>
                <div className="gal-modal-feats">
                  {[
                    { label:"Health Status", val:"✅ Vaccinated & Certified" },
                    { label:"Delivery",      val:"🚚 Free Pan India"          },
                    { label:"Age",           val:"🐣 " + modal.age + " old"   },
                    { label:"Guarantee",     val:"🛡️ 7-day Health Cover"      },
                  ].map((f, i) => (
                    <div className="gal-feat" key={i}>
                      <strong>{f.label}</strong>{f.val}
                    </div>
                  ))}
                </div>
                <div className="gal-modal-acts">
                  <button
                    className="gal-modal-cart"
                    onClick={() => { addCart(modal); setModal(null); }}
                  >
                    🛒 Add to Cart — ₹{modal.price.toLocaleString("en-IN")}
                  </button>
                  <button className="gal-modal-wa" onClick={e => waInquiry(modal, e)}>
                    💬 WhatsApp
                  </button>
                  <button className="gal-modal-wl" onClick={e => toggleWl(modal.id, e)}>
                    {wl.includes(modal.id) ? "❤️" : "🤍"}
                  </button>
                </div>
                <button
                  className="gal-buy-now"
                  onClick={() => { setModal(null); buyNow(modal); }}
                >
                  ⚡ Buy Now
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── TOAST ── */}
        <div className={"gal-toast" + (toast.on ? " on" : "")}>
          {toast.msg}
        </div>
      </div>
    </>
  );
}
